	mounted(){
		this.init();
		this.getshangpinxinxiCount();
		if(this.isAuth('shangpinxinxi','首页统计')){
			this.shangpinxinxiChat1();
		}
		this.getdingdanxinxiCount();
		if(this.isAuth('dingdanxinxi','首页统计')){
			this.dingdanxinxiChat1();
		}
		this.getyunshujiluCount();
		if(this.isAuth('yunshujilu','首页统计')){
			this.yunshujiluChat1();
		}
		this.getshangpinrukuCount();
		if(this.isAuth('shangpinruku','首页统计')){
			this.shangpinrukuChat1();
		}
		window.addEventListener('scroll', this.handleScroll)
		setTimeout(()=>{
			this.handleScroll()
		},100)
	},
	computed: {
		avatar(){
			return this.$storage.get('headportrait')?this.$storage.get('headportrait'):''
		},
	},
	methods:{
		handleScroll() {
			let arr = [
				{id:'home-title',css:'animate__fadeInUp'},
				{id:'statis1',css:'animate__fadeInUp'},
				{id:'statis2',css:'animate__fadeInUp'},
				{id:'statis3',css:'animate__fadeInUp'},
				{id:'statis4',css:'animate__fadeInUp'},
				{id:'shangpinxinxiChart1',css:'animate__fadeInUp'},
				{id:'dingdanxinxiChart1',css:'animate__fadeInUp'},
				{id:'yunshujiluChart1',css:'animate__fadeInUp'},
				{id:'shangpinrukuChart1',css:'animate__fadeInUp'},
			]
			
			for (let i in arr) {
				let doc = document.getElementById(arr[i].id)
				if (doc) {
					let top = doc.offsetTop
					let win_top = window.innerHeight + window.pageYOffset
					// console.log(top,win_top)
					if (win_top > top && doc.classList.value.indexOf(arr[i].css) < 0) {
						// console.log(doc)
						doc.classList.add(arr[i].css)
					}
				}
			}
		},
		// 统计图动画
		myChartInterval(type, xAxisData, seriesData, myChart) {
			this.$nextTick(() => {
				setInterval(() => {
					let xAxis = xAxisData.shift()
					xAxisData.push(xAxis)
					let series = seriesData.shift()
					seriesData.push(series)
				
					if (type == 1) {
						myChart.setOption({
							xAxis: [{
								data: xAxisData
							}],
							series: [{
								data: seriesData
							}]
						});
					}
					if (type == 2) {
						myChart.setOption({
							yAxis: [{
								data: xAxisData
							}],
							series: [{
								data: seriesData
							}]
						});
					}
				}, $template2.back.board.bar.base.interval);
			})
		},
		init(){
			if(this.$storage.get('Token')){
				this.$http({
					url: `${this.$storage.get('sessionTable')}/session`,
					method: "get"
				}).then(({ data }) => {
					if (data && data.code != 0) {
						router.push({ name: 'login' })
					}
				});
			}else{
				router.push({ name: 'login' })
			}
		},
		getshangpinxinxiCount() {
			this.$http({
				url: `shangpinxinxi/count`,
				method: "get"
			}).then(({
				data
			}) => {
				if (data && data.code == 0) {
					this.shangpinxinxiCount = data.data
				}
			})
		},
// 1234 折
		shangpinxinxiChat1() {
			this.$nextTick(()=>{

				var shangpinxinxiChart1 = echarts.init(document.getElementById("shangpinxinxiChart1"),'macarons');
				this.$http({
					url: `shangpinxinxi/value/shangpinmingcheng/kucunshuliang`,
					method: "get",
				}).then(({ data }) => {
					if (data && data.code === 0) {
						let res = data.data;
						let xAxis = [];
						let yAxis = [];
						let pArray = []
						for(let i=0;i<res.length;i++){
							if(this.boardBase&&i==this.boardBase.lineNum){
								break;
							}
							xAxis.push(res[i].shangpinmingcheng);
							yAxis.push(parseFloat((res[i].total)));
							pArray.push({
								value: parseFloat((res[i].total)),
								name: res[i].shangpinmingcheng
							})
						}
						var option = {};
						let titleObj = this.line.title
						titleObj.text = '商品库存量'
						
						const legendObj = this.line.legend
						let tooltipObj = { trigger: 'item',formatter: '{b} : {c}'}
						tooltipObj = Object.assign(tooltipObj , this.line.tooltip?this.line.tooltip:{})
						let xAxisObj = this.line.xAxis
						xAxisObj.type = 'category'
						xAxisObj.data = xAxis
						
						let yAxisObj = this.line.yAxis
						yAxisObj.type = 'value'
						const gridObj = this.line.grid
						
						let seriesObj = {
							data: yAxis,
							type: 'line',
						}
						seriesObj = Object.assign(seriesObj , this.line.series)
						option = {
							backgroundColor: this.line.backgroundColor,
							color: this.line.color,
							title: titleObj,
							legend: legendObj,
							grid: gridObj,
							tooltip: tooltipObj,
							xAxis: xAxisObj,
							yAxis: yAxisObj,
							series: [seriesObj]
						};
						// 使用刚指定的配置项和数据显示图表。
						shangpinxinxiChart1.setOption(option);
				
						//根据窗口的大小变动图表
						window.onresize = function() {
							shangpinxinxiChart1.resize();
						};
					}else{
						this.$message({
							message: data.msg,
							type: "warning",
							duration: 1500,
						})
					}
				});
			})
		},


		getdingdanxinxiCount() {
			this.$http({
				url: `dingdanxinxi/count`,
				method: "get"
			}).then(({
				data
			}) => {
				if (data && data.code == 0) {
					this.dingdanxinxiCount = data.data
				}
			})
		},
// 1234 竖
		dingdanxinxiChat1() {
			this.$nextTick(()=>{

				var dingdanxinxiChart1 = echarts.init(document.getElementById("dingdanxinxiChart1"),'macarons');
				this.$http({
					url: `dingdanxinxi/value/shangpinmingcheng/goumaifeiyong`,
					method: "get",
				}).then(({ data }) => {
					if (data && data.code === 0) {
						let res = data.data;
						let xAxis = [];
						let yAxis = [];
